import {
  RetrievalMode,
  defaultAgenticDeepReadConfig,
} from '@/constants/agentic-deepread';
import { cn } from '@/lib/utils';
import { Switch as AntSwitch, Form, InputNumber, Select } from 'antd';
import { ReactNode } from 'react';
import { useFormContext } from 'react-hook-form';
import { useTranslation } from 'react-i18next';
import { SwitchFormField } from './switch-fom-field';
import {
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from './ui/form';
import { NumberInput } from './ui/input';
import { RAGFlowSelect } from './ui/select';

type AntdName = string | string[];

function joinAntdName(baseName: AntdName, field: string) {
  return Array.isArray(baseName) ? [...baseName, field] : [baseName, field];
}

function AgenticHint({
  children,
  className,
}: {
  children: ReactNode;
  className?: string;
}) {
  return (
    <div className={cn('text-xs leading-5 text-muted-foreground', className)}>
      {children}
    </div>
  );
}

type RetrievalModeFormFieldProps = {
  name: string;
  label?: string;
  tooltip?: ReactNode;
};

export function RetrievalModeFormField({
  name,
  label,
  tooltip,
}: RetrievalModeFormFieldProps) {
  const form = useFormContext();
  const { t } = useTranslation();
  const retrievalModeOptions = [
    { label: t('agenticDeepRead.modes.naive'), value: RetrievalMode.Naive },
    { label: t('agenticDeepRead.modes.graph'), value: RetrievalMode.Graph },
    {
      label: t('agenticDeepRead.modes.agenticDeepRead'),
      value: RetrievalMode.AgenticDeepRead,
    },
  ];
  const fieldLabel = label ?? t('agenticDeepRead.retrievalMode');
  const fieldTooltip = tooltip ?? t('agenticDeepRead.retrievalModeTip');

  return (
    <FormField
      control={form.control}
      name={name}
      render={({ field }) => (
        <FormItem>
          <FormLabel tooltip={fieldTooltip}>{fieldLabel}</FormLabel>
          <FormControl>
            <RAGFlowSelect
              value={field.value}
              onChange={field.onChange}
              options={retrievalModeOptions}
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
}

type RetrievalModeItemProps = {
  filedName: AntdName;
  label?: string;
  tooltip?: ReactNode;
};

export function RetrievalModeItem({
  filedName,
  label,
  tooltip,
}: RetrievalModeItemProps) {
  const { t } = useTranslation();
  const retrievalModeOptions = [
    { label: t('agenticDeepRead.modes.naive'), value: RetrievalMode.Naive },
    { label: t('agenticDeepRead.modes.graph'), value: RetrievalMode.Graph },
    {
      label: t('agenticDeepRead.modes.agenticDeepRead'),
      value: RetrievalMode.AgenticDeepRead,
    },
  ];
  const fieldLabel = label ?? t('agenticDeepRead.retrievalMode');
  const fieldTooltip = tooltip ?? t('agenticDeepRead.retrievalModeTip');

  return (
    <Form.Item
      label={fieldLabel}
      tooltip={fieldTooltip}
      name={filedName}
      initialValue={RetrievalMode.Naive}
    >
      <Select options={retrievalModeOptions} />
    </Form.Item>
  );
}

function NumberFormField({
  name,
  label,
  min = 0,
}: {
  name: string;
  label: string;
  min?: number;
}) {
  const form = useFormContext();

  return (
    <FormField
      control={form.control}
      name={name}
      render={({ field }) => (
        <FormItem>
          <FormLabel>{label}</FormLabel>
          <FormControl>
            <NumberInput min={min} {...field} />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
}

function SelectFormField({ name, label }: { name: string; label: string }) {
  const form = useFormContext();
  const { t } = useTranslation();
  const retrieveStrategyOptions = [
    { label: t('agenticDeepRead.retrieveStrategies.auto'), value: 'auto' },
    { label: t('agenticDeepRead.retrieveStrategies.bm25'), value: 'bm25' },
    {
      label: t('agenticDeepRead.retrieveStrategies.hybrid'),
      value: 'hybrid',
    },
  ];

  return (
    <FormField
      control={form.control}
      name={name}
      render={({ field }) => (
        <FormItem>
          <FormLabel>{label}</FormLabel>
          <FormControl>
            <RAGFlowSelect
              value={field.value}
              onChange={field.onChange}
              options={retrieveStrategyOptions}
            />
          </FormControl>
          <FormMessage />
        </FormItem>
      )}
    />
  );
}

type AgenticDeepReadFormFieldsProps = {
  baseName: string;
  showOverride?: boolean;
  showPrebuildToggle?: boolean;
  prebuildName?: string;
  showToolCallingHint?: boolean;
  showMultiKbHint?: boolean;
};

export function AgenticDeepReadFormFields({
  baseName,
  showOverride = true,
  showPrebuildToggle = false,
  prebuildName = 'parser_config.agentic_deepread_prebuild',
  showToolCallingHint = true,
  showMultiKbHint = true,
}: AgenticDeepReadFormFieldsProps) {
  const { t } = useTranslation();

  return (
    <section className="space-y-4 rounded-lg border border-input bg-muted/20 p-4">
      <div className="space-y-1">
        <div className="text-sm font-medium">{t('agenticDeepRead.title')}</div>
        {showToolCallingHint && (
          <AgenticHint>{t('agenticDeepRead.toolCallingHint')}</AgenticHint>
        )}
        {showMultiKbHint && (
          <AgenticHint>{t('agenticDeepRead.multiKbHint')}</AgenticHint>
        )}
      </div>
      {showPrebuildToggle && (
        <SwitchFormField
          name={prebuildName}
          label={t('agenticDeepRead.prebuildCorpus')}
          tooltip={t('agenticDeepRead.prebuildCorpusTip')}
        />
      )}
      {showOverride && (
        <SwitchFormField
          name={`${baseName}.override_dataset_defaults`}
          label={t('agenticDeepRead.overrideDatasetDefaults')}
        />
      )}
      <NumberFormField
        name={`${baseName}.candidate_doc_topn`}
        label={t('agenticDeepRead.candidateDocuments')}
        min={1}
      />
      <NumberFormField
        name={`${baseName}.agent_max_rounds`}
        label={t('agenticDeepRead.agentMaxRounds')}
        min={1}
      />
      <SelectFormField
        name={`${baseName}.retrieve_strategy`}
        label={t('agenticDeepRead.retrieveStrategy')}
      />
      <NumberFormField
        name={`${baseName}.retrieve_topk`}
        label={t('agenticDeepRead.retrieveTopK')}
        min={1}
      />
      <NumberFormField
        name={`${baseName}.evidence_cap`}
        label={t('agenticDeepRead.evidenceCap')}
        min={1}
      />
      <NumberFormField
        name={`${baseName}.neighbor_window_up`}
        label={t('agenticDeepRead.neighborWindowUp')}
        min={0}
      />
      <NumberFormField
        name={`${baseName}.neighbor_window_down`}
        label={t('agenticDeepRead.neighborWindowDown')}
        min={0}
      />
    </section>
  );
}

type AgenticDeepReadItemsProps = {
  baseName: AntdName;
  showOverride?: boolean;
  showPrebuildToggle?: boolean;
  prebuildName?: AntdName;
  showToolCallingHint?: boolean;
  showMultiKbHint?: boolean;
};

export function AgenticDeepReadItems({
  baseName,
  showOverride = true,
  showPrebuildToggle = false,
  prebuildName = ['parser_config', 'agentic_deepread_prebuild'],
  showToolCallingHint = true,
  showMultiKbHint = true,
}: AgenticDeepReadItemsProps) {
  const { t } = useTranslation();
  const retrieveStrategyOptions = [
    { label: t('agenticDeepRead.retrieveStrategies.auto'), value: 'auto' },
    { label: t('agenticDeepRead.retrieveStrategies.bm25'), value: 'bm25' },
    {
      label: t('agenticDeepRead.retrieveStrategies.hybrid'),
      value: 'hybrid',
    },
  ];

  return (
    <div className="rounded-lg border border-[#e5e7eb] bg-[#fafafa] p-4">
      <div className="mb-3 text-sm font-medium">
        {t('agenticDeepRead.title')}
      </div>
      {showToolCallingHint && (
        <AgenticHint className="mb-2">
          {t('agenticDeepRead.toolCallingHint')}
        </AgenticHint>
      )}
      {showMultiKbHint && (
        <AgenticHint className="mb-4">
          {t('agenticDeepRead.multiKbHint')}
        </AgenticHint>
      )}
      {showPrebuildToggle && (
        <Form.Item
          label={t('agenticDeepRead.prebuildCorpus')}
          tooltip={t('agenticDeepRead.prebuildCorpusTip')}
          name={Array.isArray(prebuildName) ? prebuildName : [prebuildName]}
          valuePropName="checked"
        >
          <AntSwitch />
        </Form.Item>
      )}
      {showOverride && (
        <Form.Item
          label={t('agenticDeepRead.overrideDatasetDefaults')}
          name={joinAntdName(baseName, 'override_dataset_defaults')}
          valuePropName="checked"
          initialValue={defaultAgenticDeepReadConfig.override_dataset_defaults}
        >
          <AntSwitch />
        </Form.Item>
      )}
      <Form.Item
        label={t('agenticDeepRead.candidateDocuments')}
        name={joinAntdName(baseName, 'candidate_doc_topn')}
        initialValue={defaultAgenticDeepReadConfig.candidate_doc_topn}
      >
        <InputNumber min={1} style={{ width: '100%' }} />
      </Form.Item>
      <Form.Item
        label={t('agenticDeepRead.agentMaxRounds')}
        name={joinAntdName(baseName, 'agent_max_rounds')}
        initialValue={defaultAgenticDeepReadConfig.agent_max_rounds}
      >
        <InputNumber min={1} style={{ width: '100%' }} />
      </Form.Item>
      <Form.Item
        label={t('agenticDeepRead.retrieveStrategy')}
        name={joinAntdName(baseName, 'retrieve_strategy')}
        initialValue={defaultAgenticDeepReadConfig.retrieve_strategy}
      >
        <Select options={retrieveStrategyOptions} />
      </Form.Item>
      <Form.Item
        label={t('agenticDeepRead.retrieveTopK')}
        name={joinAntdName(baseName, 'retrieve_topk')}
        initialValue={defaultAgenticDeepReadConfig.retrieve_topk}
      >
        <InputNumber min={1} style={{ width: '100%' }} />
      </Form.Item>
      <Form.Item
        label={t('agenticDeepRead.evidenceCap')}
        name={joinAntdName(baseName, 'evidence_cap')}
        initialValue={defaultAgenticDeepReadConfig.evidence_cap}
      >
        <InputNumber min={1} style={{ width: '100%' }} />
      </Form.Item>
      <Form.Item
        label={t('agenticDeepRead.neighborWindowUp')}
        name={joinAntdName(baseName, 'neighbor_window_up')}
        initialValue={defaultAgenticDeepReadConfig.neighbor_window_up}
      >
        <InputNumber min={0} style={{ width: '100%' }} />
      </Form.Item>
      <Form.Item
        label={t('agenticDeepRead.neighborWindowDown')}
        name={joinAntdName(baseName, 'neighbor_window_down')}
        initialValue={defaultAgenticDeepReadConfig.neighbor_window_down}
      >
        <InputNumber min={0} style={{ width: '100%' }} />
      </Form.Item>
    </div>
  );
}

export function AgenticDeepReadToolCallingHint() {
  const { t } = useTranslation();
  return <AgenticHint>{t('agenticDeepRead.toolCallingHint')}</AgenticHint>;
}

export function AgenticDeepReadMultiKbHint() {
  const { t } = useTranslation();
  return <AgenticHint>{t('agenticDeepRead.multiKbHint')}</AgenticHint>;
}
